('campaign-1768464797732', 13, 'EoV', '[{\"id\": \"node-1768464797731-19002\", \"data\": {\"tags\": [\"History\"], \"type\": \"Lore\", \"label\": \"Halványodott nap\", \"notes\": \"A világ az elmúlt években egyre sötétebb lett, így az éjszaka teremtményei elszabadultak, és napfényben is képesek utazni/harcolni.\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7220, \"y\": 0}}, {\"id\": \"node-1768464797732-80494\", \"data\": {\"tags\": [\"History;Religion\"], \"type\": \"Lore\", \"label\": \"Az éjszaka lényei\", \"notes\": \"Vámpírok, ghoulok, zombik, szellemek, és halott/átkozott állataik\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7565, \"y\": 200}}, {\"id\": \"node-1768464797732-77807\", \"data\": {\"tags\": [\"Humans;Half-Bloods;Alliance\"], \"type\": \"Faction\", \"label\": \"A fény őrzői\", \"notes\": \"Emberek és fél vámpírok szövetsége, akik az éjszaka lényei vadászatára esküdtek\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5035, \"y\": 200}}, {\"id\": \"node-1768467101487-2409\", \"data\": {\"tags\": [\"Vampires;Clans\"], \"type\": \"Faction\", \"label\": \"Vámpír Klánok\", \"notes\": \"Dyvok Klán,\\nVoss Klán,\\nChastain Klán,\\nIlon Klán,\\nEsani Klán (Szinte kihalt)\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7565, \"y\": 400}}, {\"id\": \"node-1768467487168-517\", \"data\": {\"tags\": [\"Vampire;Clan\"], \"type\": \"Faction\", \"label\": \"Dyvok klán\", \"notes\": \"Másnéven: A Vadak\\nA hatalams fizikai erejükről ismertek, ennél már csak a brutalitásuk nagyobb\\n\\nJel mondatuk: ,,Tettek a szavak felett\\\"\\n\\n+2 strength\\n1 Rage/LR\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6875, \"y\": 600}}, {\"id\": \"node-1768467487821-3758\", \"data\": {\"tags\": [\"Vampire;Clan\"], \"type\": \"Faction\", \"label\": \"Ilon Klán\", \"notes\": \"Másnéven: A suttogók\\nAz érzelmek feletti hatalmuk miatt ismertek\\nJel mondatuk: Élesebb a késnél\\n\\n+2 cha\\n+1 con\\n\\nAdvantage on anything related to emotions\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1768467487821-3758-1769555135924-2011.jpg\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7560, \"y\": 600}}, {\"id\": \"node-1768467488519-5356\", \"data\": {\"tags\": [\"Vampire;Clan\"], \"type\": \"Faction\", \"label\": \"Chastain Klán\", \"notes\": \"Másnéven: A pásztorok\\nIsmertek arról, hogy az uralmuk alá tudják hajtani az állatokat\\nJel mondatuk: A farkas uralkodik, a féreg szenved\\n\\n+2 wis\\n+1 cha\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6070, \"y\": 600}}, {\"id\": \"node-1768467489292-6366\", \"data\": {\"tags\": [\"Vampire;Clan\"], \"type\": \"Faction\", \"label\": \"Voss Klán\", \"notes\": \"Másnéven: A vasszívűek\\nA márvány kemény bőrükről ismertek, és a telelpáthiájukról\\n\\nJel mondatuk: ,,Mindenki térdre kényszerül\\\"\\n\\n+2 con\\n+1 dex\\nResistance to phisycal dmg\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8715, \"y\": 600}}, {\"id\": \"node-1768467528880-311\", \"data\": {\"tags\": [\"Vampire;Clan\"], \"type\": \"Faction\", \"label\": \"Esani Klán\", \"notes\": \"Másnéven:A hitetlenek\\nA vér mágia mesterei, fegyvereket és páncélt tudnak készíteni belőle\\n\\n+2 con\\n+1 dex\\n\\nYou can make magical weapons\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7220, \"y\": 600}}, {\"id\": \"node-1768469247090-4663\", \"data\": {\"tags\": [\"Half-Bloods;\"], \"type\": \"Faction\", \"label\": \"Ezüst Szentrk\", \"notes\": \"Egy rend ahol félvéreket, tanítanak, az éjszakai lények vadászatára\\n\\nMinden statra +1\\n+1 vérvonaltól függően\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5150, \"y\": 400}}, {\"id\": \"node-1768469258098-6358\", \"data\": {\"tags\": [\"Humans\"], \"type\": \"Faction\", \"label\": \"A Birodalom\", \"notes\": \"Egy ősrégi birodalom, amit a tradíciók tartanak össze\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 4805, \"y\": 400}}, {\"id\": \"node-1768469706081-4646\", \"data\": {\"tags\": [\"Rituals\"], \"type\": \"Lore\", \"label\": \"Szertartások\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5265, \"y\": 600}}, {\"id\": \"node-1768471234681-4806\", \"data\": {\"tags\": [\"PC\"], \"type\": \"Character(PC)\", \"label\": \"Esani PC\", \"notes\": \"Elérhető Klasszok:\\n-Rogue\\n-Ranger\\n-Warlock\\n-Bard\\n-Blood Hunter\\n\\n\\n\\n\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7220, \"y\": 800}}, {\"id\": \"node-1768471235324-9898\", \"data\": {\"tags\": [\"PC\"], \"type\": \"Character(PC)\", \"label\": \"Chastain PC\", \"notes\": \"Elérhető klasszok:\\n-Druid\\n-Ranger\\n-Bard\\n\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6070, \"y\": 800}}, {\"id\": \"node-1768471235974-9576\", \"data\": {\"tags\": [\"PC\"], \"type\": \"Character(PC)\", \"label\": \"Voss PC\", \"notes\": \"Elérhető classok:\\n-Barbarian\\n-Ranger\\n-Rogue\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 9520, \"y\": 800}}, {\"id\": \"node-1768471236713-1011\", \"data\": {\"tags\": [\"PC\"], \"type\": \"Character(PC)\", \"label\": \"Dyvok PC\", \"notes\": \"Elérhető classok:\\n-Barbarian\\n-Fighter\\n\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6875, \"y\": 800}}, {\"id\": \"node-1768471237303-2004\", \"data\": {\"tags\": [\"PC\"], \"type\": \"Character(PC)\", \"label\": \"Ezüst Sz. PC\", \"notes\": \"Class\\n-Paladin\\n-Cleric\\n-Wizard\\n+A vérvonalad classai\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5035, \"y\": 600}}, {\"id\": \"node-1768471238125-3457\", \"data\": {\"tags\": [\"PC\"], \"type\": \"Character(PC)\", \"label\": \"Ilon PC\", \"notes\": \"Elérhető Klasszok:\\n-Bard\\n-Wizard\\n-Warlock\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7565, \"y\": 800}}, {\"id\": \"node-1768555921084-327\", \"data\": {\"tags\": [\"PC;Agenor;Esani\"], \"type\": \"Character(PC)\", \"label\": \"Gauthier de la Baie\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7335, \"y\": 1000}}, {\"id\": \"node-1768556013083-1160\", \"data\": {\"tags\": [\"PC\"], \"type\": \"Character(PC)\", \"label\": \"Lucien Varr\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 9405, \"y\": 1000}}, {\"id\": \"node-1768558023983-6979\", \"data\": {\"tags\": [\"PC;Race\"], \"type\": \"Character(PC)\", \"label\": \"Esani PC Race\", \"notes\": \"Blood Esani Traits\\n\\nCreature Type. Humanoid (vampire)\\n\\nAbility Score Increase.\\nYour Intelligence score increases by +2, and your Constitution score increases by +1.\\n\\nAge.\\nEsani reach physical maturity around 20 years, but can live for centuries.\\n\\nAlignment.\\nMost Esani lean neutral or lawful, driven by twisted faith and self-imposed judgment.\\n\\nSize.\\nMedium.\\n\\nSpeed.\\n30 ft.\\n\\nDarkvision\\n\\nYou have darkvision out to 60 feet.\\n\\nBlood Sanguimancy\\n\\nYou know the thaumaturgy cantrip.\\nAt 3rd level, you can cast cause fear once per long rest.\\nAt 5th level, you can cast vampiric touch once per long rest.\\n\\nIntelligence is your spellcasting ability for these spells.\\n\\nBloodcrafted Weapon\\n\\nAs a bonus action, you can manifest a weapon made of hardened blood in your hand.\\n\\nIt counts as a simple melee weapon you are proficient with\\n\\nDamage: 1d6 slashing or piercing\\n\\nIt is magical\\n\\nThe weapon vanishes if it leaves your hand\\n\\nYou can use this feature a number of times equal to your proficiency bonus per long rest.\\n\\nSoul Cannibalism (Limited)\\n\\nWhen a hostile creature drops to 0 HP within 5 feet of you, you may use your reaction to gain temporary hit points equal to your proficiency bonus + your Constitution modifier.\\n\\nYou can use this feature once per long rest.\\n\\nSun-Cursed Blood\\n\\nYou have disadvantage on attack rolls and Wisdom (Perception) checks that rely on sight while in direct sunlight.\\n\\nLanguages\\n\\nCommon and one other language of your choice.\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7105, \"y\": 1000}}, {\"id\": \"node-1768558407913-3649\", \"data\": {\"tags\": [\"PC;Race\"], \"type\": \"Character(PC)\", \"label\": \"Voss PC Race\", \"notes\": \"Blood Voss Traits\\n\\nCreature Type. Humanoid (vampire)\\n\\nAbility Score Increase.\\nYour Charisma score increases by +2, and your Constitution score increases by +1.\\n\\nAge.\\nVoss age slowly and often rule for centuries.\\n\\nAlignment.\\nTypically lawful evil or lawful neutral.\\n\\nSize.\\nMedium.\\n\\nSpeed.\\n30 ft.\\n\\nDarkvision\\n\\nYou have darkvision out to 60 feet.\\n\\nIronheart Flesh\\n\\nYour skin is unnaturally dense.\\n\\nWhile not wearing armor, your AC equals 13 + your Constitution modifier\\n\\nYou can still use a shield\\n\\nTelepathic Murmur\\n\\nYou can communicate telepathically with any creature you can see within 30 feet, provided it understands at least one language.\\n\\nThis does not allow mind reading.\\n\\nForce of Will\\n\\nYou have advantage on saving throws against being charmed.\\n\\nCommanding Presence\\n\\nYou gain proficiency in Intimidation or Persuasion (your choice).\\n\\nSun-Cursed Blood\\n\\nYou have disadvantage on attack rolls and Wisdom (Perception) checks that rely on sight while in direct sunlight.\\n\\nLanguages\\n\\nCommon and one other language of your choice.\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 9635, \"y\": 1000}}, {\"id\": \"node-1768902612812-4159\", \"data\": {\"tags\": [\"Officer;Danger;Voss\"], \"type\": \"NPC\", \"label\": \"Carmilla Voss\", \"notes\": \"A hang alaphangulata:\\nlágy, de nem gyenge\\nmeleg, kissé fáradt\\ntiszta artikuláció\\nmintha nem sietne sehová\\nkérdő mondatok\\nmetaforák\\nérzelmek indirekt kifejezése\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1768902612812-4159-1769756443019-5734.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8945, \"y\": 1000}}, {\"id\": \"node-1768905680164-855\", \"data\": {\"tags\": [\"Vampire;Enforcer;TheLegion;\"], \"type\": \"NPC\", \"label\": \"Marcellus Voss\", \"notes\": \"klán „hideg keze”\\nmorálisan félelmetes, de érzelmileg törékeny (Carmilla miatt)\\nAmikor eljátszod sose az járjon a fejedbe, hogy mit tenne Marcellus, hanem hogy mit tenne Carmilla\\nKülső viselkedés:\\n   keveset beszél\\n   nem fenyeget\\n   nem magyaráz\\n   dönt → végrehajt\\nmély, de nem morgó\\nnyugodt, soha nem kapkod\\nhalk, de átható\\n\\n\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1768905680164-855-1769756464821-1819.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 9175, \"y\": 1000}}, {\"id\": \"node-1769033179525-3504\", \"data\": {\"tags\": [\"Session0;Voss;LucienVarr;MarcellusVoss;\"], \"type\": \"Location\", \"label\": \"A Márvány Terem\", \"notes\": \"Amint felkel 3 cseléd nő sétál be, elég lenge ruhában, és mezitláb. Ahogy belépnek olyan különböző illatok borítják el a termet. Édesek, mint a friss tavaszi virágok, legalábbis ahogy az emlékeidben megmaradtak. Az egyik, ruhát, a másik egy kancsó vizet, hoz. Míg a harmadik meggyújtja a fáklyákat. A terem oldalán egy hatalmas 2 szárnyú ajtó van, amelyet hollók díszítenek, egy régi történetet mesél el, ami tovább van mintázva a falakon(Ha érdekli a játékost dc 15 History check ). Az ajtó kinyílik, és egy vámpír jelenik meg. Külsőre, egy kávébarna színű, ember, haját hosszú fonatokban, de konty-ban hordja, a klánod címere ott virít a mellkasán, a szemei vörösek. Rád néz, egy pillanatra a rég megfagyott véred, megáll a szervezetedben, majd az egyik cseléd lány széket hoz neki és leül. Nem szól hozzád, és nem is néz rád, de érzed hogy minden mozdulatodat figyeli. A lányok a férfi jöttére sietve befejezik a feladatukat, majd szorosan földre szegezett fejjel, egymás után kimennek a teremből.\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1769033179525-3504-1769756385846-9260.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8485, \"y\": 1000}}, {\"id\": \"node-1769033886288-3164\", \"data\": {\"tags\": [\"Voss\"], \"type\": \"Location\", \"label\": \"Voss Helyszínek\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8255, \"y\": 800}}, {\"id\": \"node-1769033934512-3401\", \"data\": {\"tags\": [\"Voss\"], \"type\": \"NPC\", \"label\": \"Voss NPC-k\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 9060, \"y\": 800}}, {\"id\": \"node-1769035632463-6749\", \"data\": {\"tags\": [\"Voss\"], \"type\": \"NPC\", \"label\": \"Session 0/Lucien Varr\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8025, \"y\": 1200}}, {\"id\": \"node-1769035669388-2044\", \"data\": {\"tags\": [\"Voss;LucienVarr;Session0\"], \"type\": \"Lore\", \"label\": \"Első Teszt\", \"notes\": \"\\n\\n\\nA Márvány Teremben, minden nélkül van ott Lucien. Marcellus azt vizsgálja, miként reagál Lucien ezekre.\\nMegtámadja e a cselédeket, kérdez-e. Mit csinál a vízzel?\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7795, \"y\": 1400}}, {\"id\": \"node-1769035775776-217\", \"data\": {\"tags\": [\"Voss;LucienVarr;Session0\"], \"type\": \"Lore\", \"label\": \"Második Teszt \", \"notes\": \"A Belső Kertben, Lucien látja ahogy egy fiatalnak tűnő vámpír, bántja azt a cselédet aki ruhát adott neki.\\nMit lép?\\n\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8255, \"y\": 1400}}, {\"id\": \"node-1769035881931-2027\", \"data\": {\"tags\": [\"Voss;LucienVarr;Session0\"], \"type\": \"Lore\", \"label\": \"Harmadik Teszt\", \"notes\": \"A kazamatában, Rengeteg Szörny/Vámpír van. Marcellus rámutat az egyikre, nem mondja meg neki mit csináljon. Vajon megöli?\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8025, \"y\": 1400}}, {\"id\": \"node-1769036230029-6520\", \"data\": {\"tags\": [\"Session0;Voss;LucienVarr;MarcellusVoss;\"], \"type\": \"Location\", \"label\": \"A Belső Kert\", \"notes\": \"Marcellus elindul kifelé a teremből.\\nNem néz vissza.\\n\\nAz ajtónál megáll egy pillanatra, majd egy apró biccentéssel jelzi,\\nhogy kövesd.\\n\\n(szünet)\\n\\nHosszú folyosókon haladtok végig.\\nA falakat festmények borítják, mindet fáklyák fénye világítja meg.\\n\\nCsaták.\\nFegyelem.\\nRend.\\n\\nNem hősies pillanatok.\\nNem szenvedés.\\n\\nCsak győzelem.\\n\\nA képeken nem látsz haragot.\\nNem látsz örömöt.\\nNem látsz fájdalmat.\\n\\n(technikai, tárgyilagos)\\nHa dobod Insightra — DC 10 — azt érzed:\\nezekben a képekben nincsenek érzelmek.\\nCsak világszemlélet.\\n\\n(rövid szünet)\\n\\nKörülbelül tíz percnyi járás után az épület megnyílik előttetek.\\n\\nA belső kertbe értek.\\n\\nAz ösvény elején Fabien Voss szobra áll.\\nTekintete lefelé néz — nem rád,\\nhanem mindenkire.\\n\\nVállán egy holló ül.\\nA szárnyai zárva.\\nA feje enyhén oldalra billenve.\\n\\nNem támad.\\nNem figyelmeztet.\\n\\nCsak lát.\\n\\n(lassabban)\\n\\nAhogy beljebb mentek, a kert megváltozik.\\n\\nNövények vesznek körül, amelyeknek még a nevét sem ismered.\\nIllatuk idegen…\\nés mégis ismerős, mintha valaha…\\nnagyon régen…\\nmár érezted volna őket.\\n\\nEgy keskeny csermely szeli ketté a kertet.\\nVize tiszta.\\nCsendesen csörgedezik.\\n\\nA túloldalon egy kis épület áll, verandával.\\nRégen emberi nemesek teáztak itt nyaranta.\\n\\nDe már nincs nap.\\nÉs nem is lesz.\\n\\nFent az égbolt tiszta.\\nA csillagok hideg fényben ragyognak —\\nmintha ezer apró szem figyelné a kertet.\\n\\n(hagyd, hogy hasson)\\n\\nÉs épp amikor kezdenél megnyugodni…\\n\\n(élesen)\\nsikoly hasít bele az éjszakába.\\n\\nNem messze tőletek.\\n\\nEgy lányt látsz a földön fekve.\\nFelismersz egy részletet a ruhájából.\\n\\nŐ az.\\nAz, aki ruhát hozott neked.\\n\\nFeletted — fölé tornyosulva — egy vámpír áll.\\nFiatal.\\nTúl fiatal.\\n\\nRánézésre alig lehet több tizenhatnál.\\n\\nDe ezt te is tudod…\\na fajtádnál ez semmit nem jelent.\\n\\nA hangja éles.\\nGúnyos.\\nSzavai lassan, élvezettel vágódnak a lányba.\\n\\nA lány nem sikolt újra.\\nMár nincs ereje hozzá.\\n\\n(szünet)\\n\\nNéhány lépéssel mögötte…\\negy másik alak áll.\\n\\nMozdulatlan.\\n\\nAhogy a hold fénye egy pillanatra rávilágít,\\nugyanaz az érzés fut végig rajtad,\\namit Marcellusnál éreztél először.\\n\\nNem félelem.\\nNem düh.\\n\\nHanem tudás.\\n\\nŐ látja ezt.\\nMindig is látta.\\n\\n(nagyon halkan)\\n\\nMarcellus nem szól.\\nNem mozdul.\\n\\nAz éjszaka vár.\\n\\n(teljes csönd — majd)\\n\\nÉs most…\\nmit teszel?\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1769036230029-6520-1769756367004-2101.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8025, \"y\": 1000}}, {\"id\": \"node-1769036957725-2761\", \"data\": {\"tags\": [\"Session0;Voss;LucienVarr;MarcellusVoss;\"], \"type\": \"Location\", \"label\": \"A várbörtön\", \"notes\": \"Marcellus nem szól.\\n\\nAz öreg vámpír pora még alig ülepszik le,\\namikor egy pillanatra rád emeli a tekintetét.\\n\\nNem kérdez.\\nNem ítélkezik.\\n\\nCsak lát.\\n\\nMajd elfordul, és egy apró biccentéssel jelzi,\\nhogy kövesd.\\n\\n(szünet)\\n\\nEgy másik úton mentek vissza az épületbe.\\n\\nNem a díszes folyosókon.\\nNem a győzelmek képei mellett.\\n\\nA falak itt kopottak.\\nA kő hideg.\\nNedves.\\n\\nAhogy haladtok, szag csap meg.\\n\\nNem rothadás.\\nNem vér.\\n\\nHanem halál — régóta itt lévő.\\n\\nMarcellus egy lépcsőhöz ér.\\nMegáll egy pillanatra.\\n\\nMajd elindul lefelé.\\n\\n(lassíts)\\n\\nElőször csak hörgést hallasz.\\n\\nTávolról.\\nElmosódva.\\n\\nAhogy haladtok lejjebb, a hangok tisztulnak.\\n\\nÜvöltések.\\nSikolyok.\\n\\nÉs olyan hangok is,\\namiket nem tudsz emberinek nevezni.\\n\\nA fáklya fénye lassan beborítja a helyet.\\n\\nCellákat látsz.\\nVasból készültek.\\n\\nNem díszesek.\\nNem rituálisak.\\n\\nÉs nem elég erősek.\\n\\nA fényre reagálnak.\\n\\nVan, aki hörög.\\nVan, aki ugat.\\nVan, aki megvadul.\\n\\nÉs van, aki térdre rogyva,\\nbocsánatért esedezik.\\n\\nMarcellus egyikükre sem néz.\\n\\nNem gyorsít.\\nNem lassít.\\n\\nElindul beljebb, a cellák közti folyosón.\\n\\n(szünet)\\n\\nItt lent minden egyes lépés\\nfelkavarja a gyomrod.\\n\\nNem tudod pontosan, mikor…\\nde egyszer csak Marcellus megáll.\\n\\nVisszanéz rád.\\n\\nMajd az egyik cellára pillant.\\n\\n(lassan)\\n\\nOdabent…\\negy romlott hullát látsz.\\n\\nA teste megvan.\\nA formája megvan.\\n\\nDe élet nincs benne.\\n\\nAhogy közelebb lépnél,\\na lény hirtelen neked ugrik.\\n\\nA mozdulat gyors.\\nŐrült.\\n\\nEgyetlen dolog állítja meg.\\n\\nA nyakán lévő lánc.\\n\\nA vas megfeszül.\\nA lény hörög.\\n\\nA szája tátva.\\nA tekintete üres.\\n\\n(hagyj időt)\\n\\nMarcellus ekkor előrelép.\\n\\nEgy kulcsot nyújt feléd.\\n\\nNem dobja.\\nNem erőlteti.\\n\\nCsak a kezedbe teszi.\\n\\nMajd két lépést hátralép.\\n\\nNem néz a cellára.\\nNem néz rád.\\n\\nA hangja most először szólal meg\\na kert óta.\\n\\nNyugodtan.\\nTényszerűen.\\n\\n„Ez az, ami marad.”\\n\\n(csend)\\n\\nA kulcs hideg a kezedben.\\n\\nA lény rángatózik a láncon.\\n\\nMarcellus vár.\\n\\nÉs most…\\nmit teszel?\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1769036957725-2761-1769756421660-5077.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8715, \"y\": 1000}}, {\"id\": \"node-1769039039195-7680\", \"data\": {\"tags\": [\"Voss;LucienVarr;Session0.5\"], \"type\": \"Lore\", \"label\": \"Encounter : Assasins\", \"notes\": \"Egy csapat bérgyilkos rátámad Lucienre, Virelle-t keresik, és hajlandóak mindnet megtenni, hogy megszerezzék tőle az infót.\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 10185, \"y\": 0}}, {\"id\": \"node-1769071615576-2474\", \"data\": {\"tags\": [\"PC\"], \"type\": \"Character(PC)\", \"label\": \"Tomi Pc/ Talon Chastain\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6070, \"y\": 1000}}, {\"id\": \"node-1769071667782-9398\", \"data\": {\"tags\": [\"PC;Session0;TalonChastain\"], \"type\": \"Lore\", \"label\": \"Session 0/Talon Chastian\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5955, \"y\": 1200}}, {\"id\": \"node-1769072319366-2544\", \"data\": {\"tags\": [\"PC;Session0;TalonChastain\"], \"type\": \"Location\", \"label\": \"A vadon\", \"notes\": \"Hajnalban járunk, most keltél fel, az elmúlt évek alatt hozzászoktál ehhez a rendhez, a nappal való kelés, és annak nyugtával történő fekvés. Most viszont valami más, az eddigi társadat Umbrát nem érzed. Eddig még sosem történt ilyen. Abban biztos vagy, hogy nem halt meg, és hogy nem sérült meg. Olyan mintha ő blokkolná a kapcsolatotokat.\\nEmiatt elindulsz a Chastain klán legközelebbi állomásához. Az utad hosszú, az évek során egyre mélyebbre kerültél a hegység erdői között. A változás olyan mintha nem csak Umbrára lenne hatással. Minden állat körülötted máshogy viselkedik, nem a megszokott módon, ez beigazolja a gyanudat, hogy valami veszélyes van készülőben. Pár óra séta után, kiérsz az sűrű erdőből. Előtted pár méterre már ott áll a helyörség. Falai szépek, a klánod címerét hordozzák a két farkas jelképét. Egy fajta honvágy fog el amint meglátod, mintha mindig is itt kellett volna lenned. Odaérve két őr fogad a kapunál, és kérdezik: ,,Mit keresel itt friss vér?\\\". Majd ha elmondja a dolgát, beengedik. Odabent rögtön a helyörség vezetőjéhez vezetnek akinek éppen vendége van. A helyörség parancsnoka a legendás Loar Chastain. Kinézete hegekkel borított, még is lehet látni alatta az embert. Kedves vonásai vannak, amik mint egy rég kiszáradt folyó maradtak rajta egy másik életből. A vendége egy fiatal vámpír hölgy, ránézésre nemes lehet, méghozzá magas rendű. Magát Virelleként mutatja be. Furcsa klán nevet nem mondott, ez a vámpíroknál íratlan törvény. Kinézete páratlan. Gyönyörű minden vonása a tökéletesség megtestesítője. A mozdulatai kecsesek, a hangja pedig egy éneklő madáréhoz hasonló, olyanéhoz amit a mai napig minden alkalommal szívesen hallgattál. Bent elmondod miért jöttél, a parancsnok nem lepődig meg, és nem is válaszol érzelmesen. ,,Értem, ez mindenképpen aggodalomra adhat okot\\\". \\\"Menj Augustinban, és láss\\\".  Az ifjú hölgy is elköszön ahogy látja hogy indulnál, megölel majd a füledbe súgja: ,,Umbra\\\".  Majd visszaül és folytatja beszélgetését a parancsnokkal. Az úton Augusting felé tartó uton, inkább a természetes ösvényeket választottad, az otthonosabbannak érződik mint az utak magánya. Ahogy haladsz előre egy mezőhöz érsz, furcsa hely ez, olyan mintha  a környék állatai békességben élnének, és egymást nem vadászó utópiában. A közepén egy ember ül, furulyával a szájába. A vállán egy holló ül, olyan akit bármikor felismernél, miatta is indultál el. A dallam egyszerű.\\nNem gyors.\\nNem szomorú.\\n\\nPont olyan, amilyennek nem szabadna léteznie itt.\\n\\nAhogy közelebb érsz, az állatok nem futnak szét.\\nNem húzódnak félre.\\nNem figyelnek rád.\\n\\nMintha nem lennél része a hierarchiának ebben a pillanatban.\\n\\nA holló a férfi vállán megmozdul.\\nOldalra billenti a fejét.\\n\\nIsmered ezt a mozdulatot.\\n\\nNem a tollakból.\\nNem a színből.\\n\\nHanem abból, ahogyan néz.\\n\\nUmbra nem szól.\\nNem rebben.\\n\\nDe tudod, hogy lát téged.\\n\\nA férfi nem fordul meg azonnal.\\nVégigjátssza a dallamot.\\n\\nCsak akkor engedi le a furulyát, amikor az utolsó hang elhal a mező fölött.\\n\\n–\\n(itt hagysz egy fél másodperc csöndet az asztalnál)\\n–\\n\\n„Ha közelebb jössz, megtöröd.”\\n\\nNem fenyegetés.\\nMegállapítás.\\n\\nA férfi végre feléd fordul.\\n\\nFiatal.\\nTúl fiatal ahhoz, hogy itt legyen.\\nTúl nyugodt ahhoz, hogy féljen.\\n\\nA tekintete nem emberi, de nem is vámpíré.\\n\\nValami… köztes.\\n\\nUmbra ekkor mozdul először.\\n\\nNem repül el.\\nNem jön hozzád.\\n\\nCsak átsétál a férfi válláról a karjára.\\n\\nEngedelmesen.\\n\\nEz nem fájdalom.\\nNem harag.\\n\\nEz elvesztett elsőbbség.\\n\\nA férfi rád néz, és halványan elmosolyodik.\\n\\n„Nem vettem el tőled.”\\n\\n(egy lépést tesz feléd)\\n\\n„Ő döntött.”\\n\\nA mező körül egy őz lép elő a fűből.\\nUtána egy róka.\\nEgy farkas a távolban leül.\\n\\nNem vadásznak.\\nNem menekülnek.\\n\\nHallgatnak.\\n\\nA férfi letérdel, hogy egy szinten legyen veled.\\n\\n„A világ változik, pásztor.”\\n\\nEz az első szó, ami igazán neked szól.\\n\\n„Aki eddig vezette, most kérdez.”\\n\\nUmbra végre feléd fordítja a fejét.\\n\\nNem kér segítséget.\\nNem kér parancsot.\\n\\nCsak… vár.\\n\\nA férfi felegyenesedik, és félreáll a mező közepéről.\\n\\n„Most rajtad a sor.”\\n\\nA dallam nem szól tovább.\\nAz állatok nem mozdulnak.\\n\\nA világ nem dönt helyetted.\\n\\nÉs most…\\nmit teszel?\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5955, \"y\": 1400}}, {\"id\": \"node-1769073693636-6821\", \"data\": {\"tags\": [\"PC;Session0;TalonChastain\"], \"type\": \"Lore\", \"label\": \"A mező\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5725, \"y\": 1400}}, {\"id\": \"node-1769073696350-9212\", \"data\": {\"tags\": [\"PC;Session0;TalonChastain\"], \"type\": \"Location\", \"label\": \"Chastain állomás\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6185, \"y\": 1400}}, {\"id\": \"node-1769078779835-9046\", \"data\": {\"tags\": [\"Pokolkopó;LoarChastain;Legenda\"], \"type\": \"NPC\", \"label\": \"Loar Chastain\", \"notes\": \"Loar egy ősrégi vámpír. Az egyik legidősebb a klánban, Háborúban szerzett hírnevet, és titulust. A Chastain pokolkopója cím\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5495, \"y\": 1200}}, {\"id\": \"node-1769079081788-287\", \"data\": {\"tags\": [\"Aplha;Tirel;Animals\"], \"type\": \"NPC\", \"label\": \"Tirel Károly\", \"notes\": \"Egyszerű férfi, de sötét titkot rejt, minnél távolabb él a társadalomtól\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5725, \"y\": 1600}}, {\"id\": \"node-1769079326677-3184\", \"data\": {\"tags\": [\"PC;Session0;TalonChastain;Umbra\"], \"type\": \"Character(PC)\", \"label\": \"Umbra\", \"notes\": \"Talon Chastain lelki vezetője, ő mutat neki irányt, gyakran a legkellemetlenebb módon. Most azonban eltünt, vajon ez is egy jel/teszt?\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6645, \"y\": 1200}}, {\"id\": \"node-1770714081444-5610\", \"data\": {\"tags\": [\"Session1;Talon;Lucien;Esani;Voss;Chastain;Augustin\"], \"type\": \"Lore\", \"label\": \"Session 1\", \"notes\": \"Megismerkedtetés:\\nA játékosok Augustin egyik városrészében a Pihe Szigeten állnak. Éppen most éreztek be a városba. Elég nagy nyüzsgés és mozgás van Augustin  előterén. Mind a hármukat kizsebeli egy kis srác, akit egy dc 5-s checkel észrevesznek. Mind a hármuktól ellopott valami fontosat, térképet, pénzt, a klán címerét. Majd elkezd elmenekülni, ha utána mennek, akkor az Alagutak fele kezd futni.  \", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7020, \"y\": 2200}}, {\"id\": \"node-1770725075498-2003\", \"data\": {\"tags\": [\"Session1;Talon;Lucien;Guither\"], \"type\": \"NPC\", \"label\": \"Piheszáll Rikk\", \"notes\": \"12 éves, A Piheszigeten él mióta eszét tudja. Már kiskorától csak a tolvajlásból tud megélni ő is, és a családja is. A családja hasonló képpen elhagyott gyerekekből áll.  Lop a játékosoktól. A NyomorNegyed alatt él -> Oda a csatornákon keresztül lehet elljutni. \\nStátusz: ÉL\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1770725075498-2003-1770726838262-2015.jpg\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6760, \"y\": 2000}}, {\"id\": \"node-1770726311910-2038\", \"data\": {\"tags\": [\"Session1;PiheszállRikk;Augustin\"], \"type\": \"Faction\", \"label\": \"Elfeledettek\", \"notes\": \"Egy nyomornegyedi gyerekekből összetevődő csoport, vezetőjük Torkos Attila\\n\\nSession1:\\n-A party odament és a harc közben szét széledt a társaság, törzshelyük elpusztult\\n\\nSesson2:\\n-Attila betör hozzájuk,  és az övét keresi, de nem találja, a vámpírok kifaggatják, de majd egy sereg holló segítségével elmenekül\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1770726311910-2038-1770730939090-5608.jpg\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6420, \"y\": 1820}}, {\"id\": \"node-1770726936573-6295\", \"data\": {\"tags\": [\"Augustin;Session1;Esani;Virelle;PatienceDeLeón\"], \"type\": \"Location\", \"label\": \"Augustin\", \"notes\": \"\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1770726936573-6295-1770726950915-4399.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7180, \"y\": 1700}}, {\"id\": \"node-1770726988623-4132\", \"data\": {\"tags\": [], \"type\": \"Location\", \"label\": \"Pihesziget\", \"notes\": \"https://www.youtube.com/watch?v=UlbxDQMo1o4\\nDark Academia Classical Music\\nhttps://www.youtube.com/watch?v=XGC80iRS7tw\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7200, \"y\": 1920}}, {\"id\": \"node-1770727004853-2930\", \"data\": {\"tags\": [], \"type\": \"Location\", \"label\": \"Nyomor Negyed\", \"notes\": \"Zene\\nhttps://www.youtube.com/watch?v=_RsnVOK6Fdg&t=9s\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7440, \"y\": 1920}}, {\"id\": \"node-1770727026850-2803\", \"data\": {\"tags\": [], \"type\": \"Location\", \"label\": \"CsontPiac\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7700, \"y\": 1920}}, {\"id\": \"node-1770727040102-8662\", \"data\": {\"tags\": [], \"type\": \"Location\", \"label\": \"Alagutak\", \"notes\": \"Ambient\\nhttps://www.youtube.com/watch?v=pv7sc85UZ-4\\nZene\\nhttps://www.youtube.com/watch?v=fq8OSrIUST4\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7900, \"y\": 1920}}, {\"id\": \"node-1770731104697-4300\", \"data\": {\"tags\": [\"Elfeledettek;PiheszállRikk\"], \"type\": \"Location\", \"label\": \"Torkos Attila\", \"notes\": \"Az Elfeledettek vezére, egy 15 éves tömzsi gyerek, aki a többiek adagját is simán betudja fali, emellett különös érzéke van a menedzserkedéshez és a vezetéshez. Egy kis királyságot alakított ki magának az Alagutakban. Az Elfeledettek alapítója\\n\\nNem tudni hogy él-e (ÉL)\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1770731104697-4300-1770731947836-6018.jpg\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6420, \"y\": 2020}}, {\"id\": \"node-1770892056608-6716\", \"data\": {\"tags\": [], \"type\": \"NPC\", \"label\": \"Boss Music\", \"notes\": \"https://www.youtube.com/watch?v=dHvElwCbFOs\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8000, \"y\": 2060}}, {\"id\": \"node-1770892253771-4195\", \"data\": {\"tags\": [], \"type\": \"Location\", \"label\": \"Báli zene\", \"notes\": \"https://www.youtube.com/watch?v=vjEUIlH9zMw\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7660, \"y\": 2140}}, {\"id\": \"node-1771837496727-2453\", \"data\": {\"tags\": [], \"type\": \"NPC\", \"label\": \"Violet Sirk\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7360, \"y\": 2240}}, {\"id\": \"node-1771838220735-71\", \"data\": {\"tags\": [], \"type\": \"Location\", \"label\": \"New Node\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7600, \"y\": 2320}}, {\"id\": \"node-1772094287635-3629\", \"data\": {\"tags\": [\"Session1;Session2;Merchatnt;CsontPiac;Kereskedő;Quest;\"], \"type\": \"NPC\", \"label\": \"Aranybéli László\", \"notes\": \"Lucien meggyőzte őt, hogy adjon neki egy doboz répát ingyen, és majd visszahozza az árát, mert drágábban elfogja adni.  Majd a 2. Sessionben vissza is vitte az ár amiért elad 1 doboz répát az 20 rézpengő, Lucien 35-t adott neki. Nagyon pozitív véleménye van Lucienről igen csak róla. Megkéri a Rokonát hogy segítsen a partynak átjutni a csontkapun\\n\\nLucien +++\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1772094287635-3629-1772097453177-4434.jpg\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6640, \"y\": 2720}}, {\"id\": \"node-1772094519304-7194\", \"data\": {\"tags\": [\"Session2;Session3;Irnok;Aranysor;Aranybéli\"], \"type\": \"NPC\", \"label\": \"Tövisvégi János\", \"notes\": \"Aranybéli László rokona, 1-2 hetente meglátogatja Lászlót. \\n\\n\\n\\nViselkedése:\\n-Gyorsan beszél, dadog\\n-Kedves, de nem Naív\\n\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1772094519304-7194-1772097411897-9746.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6260, \"y\": 2880}}, {\"id\": \"node-1772094618688-614\", \"data\": {\"tags\": [\"Session2;Session3;Virelle;\"], \"type\": \"NPC\", \"label\": \"Vörös Ifjú\", \"notes\": \"Egy fiatal 20-n éves srác, arany fürtjei vannak, kék szemmel. A ruhájáról kapta a Vörös Ifjú nevet, ami egy tetőtől talpig vörös katonai egyenruha\\n\\nŐ vámolja és jegyzi fel a kikőtőn keresztül behozott árúkat\\n\\n-Viselkedése:\\n-Gyanakvó, Politikus, \\n\\nHa elvégzik a questet:\\n-Party +\\n-3 aranykígyó, direkt nem sárkány\\n-Piheszáll Rikk, búvóhelyéről információ\\nHa nem:\\n-Party --\\n-Keresztbe fog nekik tenni, nem nyilvánvaló módon\\n-Megvásárolja Rikktől az emblémákat, és 10 aranysárkány/emblémáért, meglehet tőle venni\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1772094618688-614-1772097474825-4776.jpg\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7300, \"y\": 2820}}, {\"id\": \"node-1772095959081-2602\", \"data\": {\"tags\": [\"Kereskedő;Attilaőv;Quest\"], \"type\": \"NPC\", \"label\": \"Taratok Avaler\", \"notes\": \"A játékosok hitelre vásároltak tőle infót. Majd odaadták neki Attila övét. A játékosok tőle kapták az infót az Elfeledettekről, és Attiláról, akit nem nevezett nevevén(Avalamicsoda)\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1772095959081-2602-1772097463676-6934.jpg\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6640, \"y\": 2300}}, {\"id\": \"node-1772097514062-9548\", \"data\": {\"tags\": [], \"type\": \"Lore\", \"label\": \"Session 2\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6960, \"y\": 2620}}, {\"id\": \"node-1772098645344-811\", \"data\": {\"tags\": [\"Quest;Session2;Aranybéli;János;Tövisvégi;László\"], \"type\": \"Quest\", \"label\": \"Találkozás, Bejutás a Csontkapu túl oldalára\", \"notes\": \"Lucien megkérdezte Aranybéli Lászlót, hogy tudna-e segíteni a csapatnak a Csontkapu túl oldalára jutni. Azt mondta hogy ő nem de egy rokona 3 nap múlva ellátogat hozzá. Ő a Csontkapu másik oldalán lakik, és hátha ő betudja vinni őket.\\n\\nCsütörtök Dél\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6580, \"y\": 3000}}, {\"id\": \"node-1772098780336-6581\", \"data\": {\"tags\": [\"Quest;Session2;\"], \"type\": \"Quest\", \"label\": \"Visszaszerezni a Klánok emblémáját\", \"notes\": \"Az emblémák amiket az Elfeledettek elloptak még nem kerültek elő, Lady Virelle levelében a party tagokat a klánjuk képviselőjeként hívja meg. Így elengedhetetlen nekik, hogy időben visszaszerezzék\\n\\nA bál hétfőn lesz (6 nap múlva)\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6820, \"y\": 3000}}, {\"id\": \"node-1772098896881-4886\", \"data\": {\"tags\": [\"Quest;Virelle;\"], \"type\": \"Quest\", \"label\": \"Meghívó a bálra\", \"notes\": \"Gauither nem igen figyelt oda, így 2 fekete ruhás alak simán neki ment és a kezébe tudta csúsztatni Lady Virelle meghívóját. A bál 6 nap múlva esedékes, és addig:\\n\\n-Megkell szerezniük az emblémáikat: (Nincs kész)\\n-Megfelelő öltözéket kell találniuk: (Nincs kész)\\n-Megfelelő etikettet kell tanulniuk: (Nincs kész)\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7100, \"y\": 3000}}, {\"id\": \"node-1772099258046-617\", \"data\": {\"tags\": [\"Quest;VörösIfjú;\"], \"type\": \"Quest\", \"label\": \"Patkány írtás, az Alagutakban\", \"notes\": \"A Vörös Ifjú segít visszaszerezni az emblémákat, ha kiírtják a patkányokat az alagutakból\\n\\n-2nap\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7320, \"y\": 3000}}, {\"id\": \"node-1772100079450-4962\", \"data\": {\"tags\": [\"Session2;Kocsmáros\"], \"type\": \"NPC\", \"label\": \"Nasír, a Szír\", \"notes\": \"Lucien meghívta 1 italra, és infót kért cserébe, Virelléről és a Vörös ifjúról\\n\\nLucien+\", \"imageUrl\": \"/uploads/campaigns/campaign-1768464797732/nodes/node-1772100079450-4962-1772100140801-4148.jpg\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 7540, \"y\": 2800}}]', '[{\"id\": \"node-1768464797731-19002-node-1768464797732-80494\", \"type\": \"smoothstep\", \"source\": \"node-1768464797731-19002\", \"target\": \"node-1768464797732-80494\"}, {\"id\": \"node-1768464797731-19002-node-1768464797732-77807\", \"type\": \"smoothstep\", \"source\": \"node-1768464797731-19002\", \"target\": \"node-1768464797732-77807\"}, {\"id\": \"reactflow__edge-node-1768464797732-80494-node-1768467101487-2