('campaign-1768498742154', 13, 'Phandalin Bányái', '[{\"id\": \"node-1768498742152-97373\", \"data\": {\"tags\": [\"Main\"], \"type\": \"Location\", \"label\": \"Phandalin\", \"notes\": \"Egy kis város/Falu, rönk házak\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": -5.3363227130670055, \"y\": 2.1830127201419884}}, {\"id\": \"node-1768498742152-11494\", \"data\": {\"tags\": [\"Danger;Pub\"], \"type\": \"Location\", \"label\": \"Tomblen fogadója\", \"notes\": \"Jól elvoltunk, dalolásztunk, Syldar adott küldetést, hogy pateroljuk ki a vörös köpenyesek. Pár óra szórakozás után megjelent 4 vörös köpenyes, akiket megöltünk\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 260, \"y\": 120}}, {\"id\": \"node-1768498742152-34200\", \"data\": {\"tags\": [\"danger\"], \"type\": \"Location\", \"label\": \"Alvó óriás\", \"notes\": \"A vörös köpenyesek egyik búvóhelye\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 161.15554809570312, \"y\": 251.82220458984375}}, {\"id\": \"node-1768499112172-9642\", \"data\": {\"tags\": [\"Phndalin;Danger;Evil\"], \"type\": \"Faction\", \"label\": \"Vörös köpenyesek \", \"notes\": \"Phandalin zsoldosai, rettegésben tartják a falut. A mi feladatunk kipaterolni őket. Elvileg a Polgármesternek a családja veszélyben van. Törzshelyük az Alvó Óriás\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": -140.95661302166627, \"y\": 84.22773644617769}}, {\"id\": \"node-1768507141755-7134\", \"data\": {\"tags\": [], \"type\": \"Item\", \"label\": \"Mantacore Farok\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 148.15106877631575, \"y\": -122.71268330902352}}]', '[{\"id\": \"node-1768498742152-97373-node-1768498742152-11494\", \"type\": \"smoothstep\", \"source\": \"node-1768498742152-97373\", \"target\": \"node-1768498742152-11494\"}, {\"id\": \"node-1768498742152-97373-nod