('campaign-1771768726885', 13, 'Drakkenheim', '[{\"id\": \"node-1771775180313-8373\", \"data\": {\"tags\": [\"Crafting\"], \"type\": \"Item\", \"label\": \"Carpenter Tools Crafting\", \"notes\": \"\", \"imageUrl\": \"/uploads/campaigns/campaign-1771768726885/nodes/node-1771775180313-8373-1771783981247-1076.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 1355, \"y\": 200}}, {\"id\": \"node-1771775200431-9678\", \"data\": {\"tags\": [\"recept;Uncommon;Shield;Weapons;Background\"], \"type\": \"Item\", \"label\": \"[+1 Weapon, + 1 Shield]  Recept\", \"notes\": \"Uncommon Workshop\\nAnimus: Any Animus\\nBones: Any Bones\\nAny Natural Wepaon\\nAny Hide\\n\\nEach item must come from a different monster (Different stat block)\", \"imageUrl\": \"/uploads/campaigns/campaign-1771768726885/nodes/node-1771775200431-9678-1771784453884-1222.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 1585, \"y\": 600}}, {\"id\": \"node-1771775306568-6731\", \"data\": {\"tags\": [\"recept;Uncommon;Wand;Background\"], \"type\": \"Item\", \"label\": \"[Korai élet tanonc pálcája]  Recept\", \"notes\": \"[Korai élet tanonc pálcája]  Recept\\nUncommon Wand\\n\\nOnce per turn the cantrip deals +1d4 dmg\\n\\n\\nUncommon Components\\nAny Animus\\nBones: Bones from an undead\\nDust: Fey Dust\\nFluid: Actoplasm\", \"imageUrl\": \"/uploads/campaigns/campaign-1771768726885/nodes/node-1771775306568-6731-1771784599261-9619.png\", \"statblock\": null}, \"type\": null, \"position\": {\"x\": 1815, \"y\": 600}}, {\"id\": \"node-1771775318883-210\", \"data\": {\"tags\": [\"Rarity;Recept\"], \"type\": \"Location\", \"label\": \"Common\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 665, \"y\": 400}}, {\"id\": \"node-1771775326909-6835\", \"data\": {\"tags\": [\"Rarity;Recept\"], \"type\": \"Location\", \"label\": \"Uncommon\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 1700, \"y\": 400}}, {\"id\": \"node-1771775337308-3167\", \"data\": {\"tags\": [\"Rarity;Recept\"], \"type\": \"Location\", \"label\": \"Rare\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 1355, \"y\": 400}}, {\"id\": \"node-1771775356634-7817\", \"data\": {\"tags\": [\"Rarity;Recept\"], \"type\": \"Location\", \"label\": \"Very Rare\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 2045, \"y\": 400}}, {\"id\": \"node-1771775368780-866\", \"data\": {\"tags\": [\"Rarity;Recept\"], \"type\": \"Location\", \"label\": \"Legendary\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 1125, \"y\": 400}}, {\"id\": \"node-1772374512942-855\", \"data\": {\"tags\": [\"Session1;Kereskedő;Frakciónélküli\"], \"type\": \"NPC\", \"label\": \"Arin Marlove\", \"notes\": \"Felbérelt minket\\n25 Sárkány, ebből 10-et az elején odaadott\\n\\nAlapvető élelmiszereket árul, pl sör\\n\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 5585, \"y\": 400}}, {\"id\": \"node-1772375658463-5772\", \"data\": {\"tags\": [\"Hotel;Frakciónélküli\"], \"type\": \"Location\", \"label\": \"Vörös Oroszlán Hotel\", \"notes\": \"25 arany sárkány az ár\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 8115, \"y\": 400}}, {\"id\": \"node-1772375715782-7149\", \"data\": {\"tags\": [], \"type\": \"Location\", \"label\": \"Kutyát szőrivel\", \"notes\": \"\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 6620, \"y\": 400}}, {\"id\": \"node-1772376494541-3680\", \"data\": {\"tags\": [], \"type\": \"Location\", \"label\": \"XP\", \"notes\": \"335/300 -> Level 2\\n840/900\\n1785/2700\\n\", \"imageUrl\": null, \"statblock\": null}, \"type\": null, \"position\": {\"x\": 3425, \"y\": 200}}, {\"id\": \"node-1772376801258-3047\", \"data\": {\"tags\": [], \"type\": \"NPC\", \"label